async (params, browser) => {
  // Open Transfermarkt
  await browser.open('https://www.transfermarkt.com/statistik/neuestetransfers')

  // Wait for page
  await browser.waitForSelector('.responsive-table, table.items, .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const transfers = []; document.querySelectorAll('table.items tbody tr.odd, table.items tbody tr.even').forEach((el, i) => { if (i < 20) { const playerEl = el.querySelector('td.hauptlink a'); const clubImgs = el.querySelectorAll('img.tiny_wappen, img[class*="wappen"]'); const fromClub = clubImgs[0]?.getAttribute('title') || ''; const toClub = clubImgs[1]?.getAttribute('title') || ''; const feeEl = el.querySelector('td.rechts a, td.rechts'); const ageEl = el.querySelector('td.zentriert'); transfers.push({ player: playerEl?.getAttribute('title') || playerEl?.textContent?.trim() || '', player_url: playerEl?.href ? 'https://www.transfermarkt.com' + playerEl.getAttribute('href') : '', from: fromClub, to: toClub, fee: feeEl?.textContent?.trim() || '', age: ageEl?.textContent?.trim() || '' }); } }); return { transfer_count: transfers.length, transfers };`)

  return result
}
